-- ============================================
-- Legislacao full-site: margarete-coelho / Camara Dados Abertos / projetos_lei
-- Coverage ampliado parcial: Lote A autoria principal Camara
-- ============================================
-- Fonte oficial: Camara dos Deputados - Dados Abertos
--   https://dadosabertos.camara.leg.br/api/v2/deputados/204430
--   https://dadosabertos.camara.leg.br/api/v2/proposicoes/{id}
--   https://dadosabertos.camara.leg.br/api/v2/proposicoes/{id}/autores
--
-- Artefato de auditoria:
--   fonte interna de curadoria
--
-- Coverage:
--   coverage_id    = margarete-coelho-camara-autoria-principal-ampliado-parcial-lote-a-20260506
--   coverage_scope = inventario_ampliado_parcial_camara_autoria_principal_lote_a_20260506
--
-- Filtro factual: das 100 rows Camara legacy existentes, somente 61
-- foram marcadas com coverage_id porque a API oficial confirmou
-- idDeputado=204430, tipo Deputado(a), ordemAssinatura=1.
-- 39 rows permanecem sem coverage por coautoria/sem autoria verificavel.
--
-- Esta migration NAO escreve em legislacao_mandato_executivo.
-- Esta migration NAO insere, deleta ou trunca rows.
-- ============================================

DO $$
DECLARE
  cand_id uuid;
  total_pl int;
  target_present int;
  target_with_other_coverage int;
  lme_count int;
BEGIN
  SELECT id INTO cand_id FROM candidatos WHERE slug = 'margarete-coelho';

  IF cand_id IS NULL THEN
    RAISE NOTICE 'margarete-coelho: candidato ausente neste banco local/CI minimo; coverage Camara pulado';
    RETURN;
  END IF;

  SELECT count(*) INTO total_pl FROM projetos_lei WHERE candidato_id = cand_id;
  IF total_pl <> 100 THEN
    RAISE EXCEPTION 'Pre-condicao margarete-coelho: esperadas 100 rows legacy em projetos_lei, encontradas %', total_pl;
  END IF;

  SELECT count(*) INTO target_present
  FROM projetos_lei
  WHERE candidato_id = cand_id
    AND fonte = 'Camara'
    AND proposicao_id_api IN ('2342326', '2333890', '2317872', '2313291', '2306836', '2334429', '2342324', '2334428', '2320547', '2317756', '2342323', '2333936', '2319624', '2317880', '2317755', '2341643', '2333931', '2317878', '2304833', '2321496', '2317757', '2304161', '2300345', '2298940', '2298115', '2297672', '2297072', '2294452', '2304835', '2303556', '2298937', '2298108', '2297554', '2291546', '2300346', '2299965', '2298505', '2297883', '2297513', '2294677', '2300143', '2298506', '2298058', '2297547', '2295792', '2293285', '2298931', '2297553', '2295793', '2344639', '2318842', '2304581', '2293284', '2342331', '2342325', '2342330', '2342329', '2310697', '2300144', '2298073', '2342328');
  IF target_present <> 61 THEN
    RAISE EXCEPTION 'Pre-condicao margarete-coelho: esperadas 61 rows alvo Camara presentes, encontradas %', target_present;
  END IF;

  SELECT count(*) INTO target_with_other_coverage
  FROM projetos_lei
  WHERE candidato_id = cand_id
    AND proposicao_id_api IN ('2342326', '2333890', '2317872', '2313291', '2306836', '2334429', '2342324', '2334428', '2320547', '2317756', '2342323', '2333936', '2319624', '2317880', '2317755', '2341643', '2333931', '2317878', '2304833', '2321496', '2317757', '2304161', '2300345', '2298940', '2298115', '2297672', '2297072', '2294452', '2304835', '2303556', '2298937', '2298108', '2297554', '2291546', '2300346', '2299965', '2298505', '2297883', '2297513', '2294677', '2300143', '2298506', '2298058', '2297547', '2295792', '2293285', '2298931', '2297553', '2295793', '2344639', '2318842', '2304581', '2293284', '2342331', '2342325', '2342330', '2342329', '2310697', '2300144', '2298073', '2342328')
    AND coverage_id IS NOT NULL
    AND coverage_id <> 'margarete-coelho-camara-autoria-principal-ampliado-parcial-lote-a-20260506';
  IF target_with_other_coverage <> 0 THEN
    RAISE EXCEPTION 'Pre-condicao margarete-coelho: % rows alvo ja tem coverage_id divergente', target_with_other_coverage;
  END IF;

  SELECT count(*) INTO lme_count FROM legislacao_mandato_executivo WHERE candidato_id = cand_id;
  IF lme_count <> 0 THEN
    RAISE EXCEPTION 'Pre-condicao margarete-coelho: legislacao_mandato_executivo deve permanecer 0, encontrado %', lme_count;
  END IF;
END $$;

